// vsnprintf implementation
static int _print_itoa(char *buf, long val, int base, int uppercase, int width, int pad_zero, int sign) {
    char tmp[32];
    const char *digits = uppercase ? "0123456789ABCDEF" : "0123456789abcdef";
    unsigned long uval = sign ? (unsigned long)(-(val < 0 ? val : -val)) : (unsigned long)val;
    if (sign && val < 0) uval = (unsigned long)(-(long)val);
    else uval = (unsigned long)val;
    int neg = (sign && val < 0);
    int i = 0;
    if (uval == 0) tmp[i++] = '0';
    else while (uval > 0) { tmp[i++] = digits[uval % base]; uval /= base; }
    int len = i;
    if (neg) len++;
    if (width > 0 && !pad_zero) {
        for (int j = len; j < width; j++) { *buf++ = ' '; }
    }
    if (neg) *buf++ = '-';
    if (width > 0 && pad_zero) {
        for (int j = len; j < width; j++) { *buf++ = '0'; }
    }
    while (i > 0) *buf++ = tmp[--i];
    return (width > len) ? width : len;
}

int vsnprintf(char *str, size_t size, const char *fmt, va_list ap) {
    char *out = str;
    char *end = str + size - 1;
    if (size == 0) return 0;
    while (*fmt && out < end) {
        if (*fmt != '%') { *out++ = *fmt++; continue; }
        fmt++;
        int pad_zero = 0, width = 0, long_flag = 0;
        if (*fmt == '0') { pad_zero = 1; fmt++; }
        while (*fmt >= '0' && *fmt <= '9') { width = width * 10 + (*fmt - '0'); fmt++; }
        if (*fmt == 'l') { long_flag = 1; fmt++; }
        switch (*fmt) {
            case 'd': case 'i': {
                long val = long_flag ? va_arg(ap, long) : va_arg(ap, int);
                out += _print_itoa(out, val, 10, 0, width, pad_zero, 1);
                break;
            }
            case 'u': {
                unsigned long val = long_flag ? va_arg(ap, unsigned long) : va_arg(ap, unsigned int);
                out += _print_itoa(out, (long)val, 10, 0, width, pad_zero, 0);
                break;
            }
            case 'x': case 'X': {
                unsigned long val = long_flag ? va_arg(ap, unsigned long) : va_arg(ap, unsigned int);
                out += _print_itoa(out, (long)val, 16, *fmt == 'X', width, pad_zero, 0);
                break;
            }
            case 'o': {
                unsigned long val = long_flag ? va_arg(ap, unsigned long) : va_arg(ap, unsigned int);
                out += _print_itoa(out, (long)val, 8, 0, width, pad_zero, 0);
                break;
            }
            case 'p': {
                unsigned long val = (unsigned long)va_arg(ap, void *);
                *out++ = '0'; *out++ = 'x';
                out += _print_itoa(out, (long)val, 16, 0, 8, 1, 0);
                break;
            }
            case 's': {
                const char *s = va_arg(ap, const char *);
                if (!s) s = "(null)";
                while (*s && out < end) *out++ = *s++;
                break;
            }
            case 'c': {
                *out++ = (char)va_arg(ap, int);
                break;
            }
            case '%': {
                *out++ = '%';
                break;
            }
            default:
                *out++ = '%'; *out++ = *fmt; break;
        }
        fmt++;
    }
    *out = 0;
    return out - str;
}

int vsprintf(char *str, const char *fmt, va_list ap) {
    return vsnprintf(str, 0x7FFFFFFF, fmt, ap);
}

int sprintf(char *str, const char *fmt, ...) {
    va_list ap;
    va_start(ap, fmt);
    int r = vsnprintf(str, 0x7FFFFFFF, fmt, ap);
    va_end(ap);
    return r;
}

int snprintf(char *str, size_t size, const char *fmt, ...) {
    va_list ap;
    va_start(ap, fmt);
    int r = vsnprintf(str, size, fmt, ap);
    va_end(ap);
    return r;
}

int printf(const char *fmt, ...) {
    char buf[1024];
    va_list ap;
    va_start(ap, fmt);
    int r = vsnprintf(buf, sizeof(buf), fmt, ap);
    va_end(ap);
    sys_write(1, buf, r);
    return r;
}

int fprintf(FILE *fp, const char *fmt, ...) {
    char buf[1024];
    va_list ap;
    va_start(ap, fmt);
    int r = vsnprintf(buf, sizeof(buf), fmt, ap);
    va_end(ap);
    sys_write(fp->fd, buf, r);
    return r;
}
ENDOFFILE
